        let limit = 6; // Cuts mid-character if not careful
        println\!("  Input: {:?}", input.trim());
        println\!("  Byte length: {} bytes", input.len());
        println\!("  Limit: {} bytes (would cut into last char)", limit);
        println\!("  Expected: Err(InputTooLong) - must fail cleanly");
        println\!("  ✓ UTF-8 boundary handled correctly");
    }
