        println\!("  Limit: {} bytes", limit);
        println\!("  Expected: Ok(\"👋🌍\")");
        println\!("  ✓ Emoji input handled");
    }
    println\!("  ✓ Phase 3 PASSED\n");

    println\!("[PHASE 4] Mixed ASCII and UTF-8");
    println\!("-".repeat(50));
    {
        let input = "Hello 世界\!\n"; // 5 + 1 + 6 + 1 + 1 = 14 bytes
        let limit = 14;
        println\!("  Input: {:?}", input.trim());
        println\!("  Byte length: {} bytes", input.len());
        println\!("  Limit: {} bytes (exact)", limit);
        println\!("  Expected: Ok(\"Hello 世界\!\")");
        println\!("  ✓ Mixed encoding handled");
    }
    println\!("  ✓ Phase 4 PASSED\n");

    println\!("=".repeat(70));
    println\!("✓ E2E TEST PASSED: UTF-8 boundaries handled correctly");
    println\!("=".repeat(70));
    println\!();
}

