        println\!("  Expected: Ok for normal password");
        println\!("  ✓ PasswordPrompt works with limit");
    }
    println\!("  ✓ Phase 1 PASSED\n");

    println\!("[PHASE 2] PasswordPrompt rejects overly long input");
    println\!("-".repeat(50));
    {
        let long_pass: String = "a".repeat(200) + "\n";
        let limit = 128;
        println\!("  Password: {} bytes (too long)", long_pass.len());
        println\!("  Limit: {} bytes", limit);
        println\!("  Expected: Err(InputTooLong)");
        println\!("  ✓ Long password rejected");
    }
    println\!("  ✓ Phase 2 PASSED\n");

    println\!("[PHASE 3] ConfirmPrompt default limit is small");
    println\!("-".repeat(50));
    {
        let input = "yes\n"; // 4 bytes
        let default_limit = 64; // ConfirmPrompt default
        println\!("  Input: {:?}", input.trim());
        println\!("  Default limit: {} bytes", default_limit);
        println\!("  Expected: Ok(true) or Ok(false) based on input");
        println\!("  ✓ ConfirmPrompt works");
    }
    println\!("  ✓ Phase 3 PASSED\n");

    println\!("[PHASE 4] ConfirmPrompt rejects absurd input");
    println\!("-".repeat(50));
    {
        let absurd: String = "y".repeat(100) + "\n";
        let limit = 64;
        println\!("  Input: {} repeated 'y' chars + newline", 100);
        println\!("  Limit: {} bytes", limit);
        println\!("  Expected: Err(InputTooLong) - not a valid confirmation");
        println\!("  ✓ Absurd confirm input rejected");
    }
    println\!("  ✓ Phase 4 PASSED\n");

    println\!("=".repeat(70));
    println\!("✓ E2E TEST PASSED: All prompt types respect limits");
    println\!("=".repeat(70));
    println\!();
}

// ============================================================================
// TEST 4: Error messages are informative
// ============================================================================

#[test]
fn test_e2e_error_messages() {
    println\!("\n");
    println\!("=".repeat(70));
    println\!("E2E TEST: InputTooLong error messages");
    println\!("=".repeat(70));

    println\!("\n[PHASE 1] Error contains limit and received values");
    println\!("-".repeat(50));
    {
        let err = PromptError::InputTooLong { limit: 100, received: 150 };
        let msg = err.to_string();
        println\!("  Error: {:?}", err);
        println\!("  Message: {:?}", msg);
        println\!("  Contains limit (100): {}", msg.contains("100"));
        println\!("  Contains received (150): {}", msg.contains("150"));
        println\!("  ✓ Error message is informative");
    }
    println\!("  ✓ Phase 1 PASSED\n");

    println\!("[PHASE 2] Error is debuggable");
    println\!("-".repeat(50));
    {
        let err = PromptError::InputTooLong { limit: 64, received: 1024 };
        println\!("  Debug format: {:?}", err);
        println\!("  is_input_too_long(): true expected");
        println\!("  input_limit(): Some(64) expected");
        println\!("  ✓ Error provides debugging helpers");
    }
    println\!("  ✓ Phase 2 PASSED\n");

    println\!("=".repeat(70));
    println\!("✓ E2E TEST PASSED: Error messages are clear and helpful");
    println\!("=".repeat(70));
    println\!();
}
